import NumberBox from "~/components/public/numberBox";
import CountDown from "~/components/public/countDown";
import { mapActions } from "vuex";
import { Message } from "element-ui";
export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
      link: [
        {
          rel: "icon",
          type: "image/x-icon",
          href: this.$store.getters.favicon,
        },
      ],
    };
  },
  components: {
    NumberBox,
    CountDown,
  },
  async asyncData({ params, $get, app }) {
    const { data, code, msg } = await $get("goods/getGoodsDetail", {
      params: { id: params.id },
    });
    if (code == 0) {
      Message({
        message: msg,
        type: "error",
      });
      setTimeout(() => app.router.back(), 1500);
    }
    return {
      goodsDetails: data,
      goodsImage: data.goods_image,
      activity: data.activity,
    };
  },

  data() {
    return {
      goodsDetails: {},
      goodsImage: [],
      activity: {},
      swiperOptions: {
        pagination: {
          el: ".swiper-pagination",
          clickable: true,
        },
        navigation: {
          nextEl: ".swiper-button-next",
          prevEl: ".swiper-button-prev",
        },
        preventClicks: true,
        slidesPerView: "auto",
      },
      active: "0",
      commentActive: 0,
      swiperIndex: 0,
      checkedGoods: {},
      comment: {},
      goodsNum: 1,
      goodsSpec: [],
      id: "",
      timeData: {}
    };
  },
  created() {
    this.id = this.$route.params.id;
    this.getComment(this.id);
  },
  methods: {
    ...mapActions(["getPublicData"]),
    onClickSlide(e) {
      this.swiperIndex = e;
    },
    onChoseSpecItem(id, specid) {
      const { goodsSpec } = this;
      goodsSpec.forEach((item) => {
        if (item.spec_value && item.id == id) {
          item.spec_value.forEach((specitem) => {
            specitem.checked = 0;
            if (specitem.id == specid) {
              specitem.checked = 1;
            }
          });
        }
      });
      this.goodsSpec = [...goodsSpec];
    },
    async onAddCart() {
      const {
        goodsNum,
        checkedGoods: { id },
      } = this;
      const { code, data, msg } = await this.$post("/cart/add", {
        item_id: id,
        goods_num: goodsNum,
      });
      if (code == 1) {
        this.getPublicData();
        this.$message({
          message: msg,
          type: "success",
        });
      }
    },
    onBuyNow() {
      const {
        goodsNum,
        checkedGoods: { id },
      } = this;
      const goods = [
        {
          item_id: id,
          num: goodsNum,
        },
      ];
      this.$router.push({
        path: "/confirm_order",
        query: {
          data: encodeURIComponent(
            JSON.stringify({
              goods,
            })
          ),
        },
      });
    },
    async getGoodsDetail() {
      const { data, code } = await this.$get("goods/getGoodsDetail", {
        params: { id: this.id },
      });
      if (code == 1) {
        this.goodsDetails = data;
      }
    },
    async onCollectionGoods() {
      const {
        goodsDetails: { is_collect },
      } = this;
      const { data, code } = await this.$post("collect/handleCollectGoods", {
        is_collect: is_collect == 0 ? 1 : 0,
        goods_id: this.id,
      });
      if (code == 1) {
        if (is_collect == 0) {
          this.$message({
            message: "收藏成功",
            type: "success",
          });
        } else {
          this.$message({
            message: "取消收藏成功",
            type: "success",
          });
        }
        this.getGoodsDetail();
      }
    },
    async getComment() {
      const { data, code } = await this.$get("/goods_comment/category", {
        params: { goods_id: this.id },
      });
      if (code == 1) {
        this.comment = data;
        this.commentActive = data.comment[0].id;
      }
    },
      onChangeDate(e) {
        let timeData = {}
        for (let prop in e) {
            if (prop !== 'milliseconds') timeData[prop] = ('0' + e[prop]).slice(-2)
        }
        this.timeData = timeData
    },
  },
  watch: {
    goodsSpec: {
      immediate: true,
      handler(value) {
        const { goods_item } = this.goodsDetails;
        let keyArr = [];
        value.forEach((item) => {
          if (item.spec_value) {
            item.spec_value.forEach((specitem) => {
              if (specitem.checked) {
                keyArr.push(specitem.id);
              }
            });
          }
        });
        if (!keyArr.length) return;
        let key = keyArr.join(",");
        let index = goods_item.findIndex((item) => {
          return item.spec_value_ids == key;
        });
        if (index == -1) {
          index = 0;
        }
        this.checkedGoods = goods_item[index];
        console.log(this.checkedGoods);
      },
    },
    goodsDetails: {
      immediate: true,
      handler(value) {
        if (!value.goods_spec) return;
        value.goods_spec.forEach((item) => {
          item.spec_value.forEach((specitem, specindex) => {
            if (specindex == 0) {
              specitem.checked = 1;
            } else {
              specitem.checked = 0;
            }
          });
        });
        this.goodsSpec = [...value.goods_spec];
      },
    },
  },
  computed: {
    countTime() {
      const info = this.activity.info;
      return info ? info.end_time - Date.now() / 1000 : 0;
    },
  },
};
