export default {
  components: {},
  props: {
    list: {
      type: Array,
      default: () => [],
    },
    type: Number,
    goodsId: [String, Number],
  },
  data() {
    return {
      commentList: [],
      count: 0,
      page: 1,
    };
  },
  created() {
    this.getCommentList();
  },
  methods: {
    async getCommentList() {
      const { data, code } = await this.$get("goods_comment/lists", {
        params: {
          id: this.type,
          goods_id: this.goodsId,
          page_size: 10,
          page_no: this.page,
        },
      });
      if (code == 1) {
        this.commentList = data.list;
        this.count = data.count;
      }
    },
    changePage(current) {
      this.page = current;
      this.getCommentList();
    },
  },
};
